import { Canvas } from '@react-three/fiber';
import { OrthographicCamera } from '@react-three/drei';
import { useState, useCallback } from 'react';

interface InfiniteCanvasProps {
  zoom: number;
  onZoomChange: (zoom: number) => void;
  onPanChange?: (x: number, y: number) => void;
}

// Constants matching POC
const MIN_ZOOM = 0.1;
const MAX_ZOOM = 5.0;

// Placeholder content - will be replaced with LOD layers in F105+
function PlaceholderContent() {
  return (
    <>
      {/* Grid of reference points */}
      {Array.from({ length: 11 }, (_, i) => (
        <mesh key={`h-${i}`} position={[0, (i - 5) * 24, 0]}>
          <planeGeometry args={[1000, 1]} />
          <meshBasicMaterial color="#e1e8ed" />
        </mesh>
      ))}
      {Array.from({ length: 21 }, (_, i) => (
        <mesh key={`v-${i}`} position={[(i - 10) * 50, 0, 0]}>
          <planeGeometry args={[1, 240]} />
          <meshBasicMaterial color="#e1e8ed" />
        </mesh>
      ))}

      {/* Center marker */}
      <mesh position={[0, 0, 0.1]}>
        <circleGeometry args={[10, 32]} />
        <meshBasicMaterial color="#5c7080" />
      </mesh>

      {/* Origin label */}
      <mesh position={[0, 0, 0.2]}>
        <planeGeometry args={[60, 20]} />
        <meshBasicMaterial color="#f5f8fa" />
      </mesh>
    </>
  );
}

export function InfiniteCanvas({ zoom, onZoomChange, onPanChange }: InfiniteCanvasProps) {
  const [isPanning, setIsPanning] = useState(false);
  const [panStart, setPanStart] = useState({ x: 0, y: 0 });
  const [cameraPos, setCameraPos] = useState({ x: 0, y: 0 });

  // Handle wheel zoom (zoom toward cursor)
  const handleWheel = useCallback((e: React.WheelEvent) => {
    e.preventDefault();
    const delta = e.deltaY > 0 ? 0.9 : 1.1;
    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, zoom * delta));
    onZoomChange(newZoom);
  }, [zoom, onZoomChange]);

  // Handle pan start
  const handlePointerDown = useCallback((e: React.PointerEvent) => {
    setIsPanning(true);
    setPanStart({ x: e.clientX, y: e.clientY });
    (e.target as HTMLElement).setPointerCapture(e.pointerId);
  }, []);

  // Handle pan move
  const handlePointerMove = useCallback((e: React.PointerEvent) => {
    if (!isPanning) return;

    const dx = (e.clientX - panStart.x) / zoom;
    const dy = (e.clientY - panStart.y) / zoom;

    setCameraPos(pos => {
      const newX = pos.x - dx;
      const newY = pos.y + dy; // Inverted for natural feel
      onPanChange?.(newX, newY);
      return { x: newX, y: newY };
    });

    setPanStart({ x: e.clientX, y: e.clientY });
  }, [isPanning, panStart, zoom, onPanChange]);

  // Handle pan end
  const handlePointerUp = useCallback((e: React.PointerEvent) => {
    setIsPanning(false);
    (e.target as HTMLElement).releasePointerCapture(e.pointerId);
  }, []);

  // Calculate frustum size based on container
  const frustumSize = 500;

  return (
    <div
      style={{
        width: '100%',
        height: '100%',
        cursor: isPanning ? 'grabbing' : 'grab',
        touchAction: 'none'
      }}
      onWheel={handleWheel}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      onPointerLeave={handlePointerUp}
    >
      <Canvas
        gl={{ antialias: true, alpha: false }}
        style={{ background: '#f4f4f5' }}
      >
        <OrthographicCamera
          makeDefault
