    A: number;
    B: number;
    C: number;
    D: number;
  };
}

interface MaintenanceType {
  level: "A" | "B" | "C" | "D";
  intervalKm: number;              // 10000, 50000, 200000, 800000
  toleranceKm: number;             // ±2000, ±5000, etc
  durationHours: number;           // 4, 16, 72, 480
  manHours: number;                // 8, 32, 160, 1200
